def count_index_per_file(rounds):
    counter = Counter()
    for r in rounds:
        counter.update(set(r))
    return dict(sorted(counter.items()))

for file, rounds in data.items():
    print(f"\n{file}")
    result = count_index_per_file(rounds)
    print({k: v for k, v in result.items() if v >= 15})
